// ── RFM Scoring in n8n ──────────────────────────────────────
const users = $('Query User LTV').all().map(i => i.json);
const now = new Date();

// Sort into quintiles
const sorted_ltv = [...users].sort((a,b) => a.lifetime_value - b.lifetime_value);
const quintile = (arr, val) => {
  const idx = arr.findIndex(x => x.lifetime_value >= val);
  const pct = idx / arr.length;
  if (pct < 0.2) return 1;
  if (pct < 0.4) return 2;
  if (pct < 0.6) return 3;
  if (pct < 0.8) return 4;
  return 5;
};

const scored = users.map(u => {
  const lastOrder = new Date(u.last_order_date || now);
  const recency   = Math.max(0, Math.floor((now - lastOrder) / 86400000));
  const m_score   = quintile(sorted_ltv, u.lifetime_value);
  const f_score   = Math.min(5, Math.max(1, Math.round(u.categories_purchased)));
  const r_score   = recency < 30 ? 5 : recency < 90 ? 4 : recency < 180 ? 3 : recency < 365 ? 2 : 1;

  let segment = 'About to Sleep';
  if (r_score >= 4 && f_score >= 4 && m_score >= 4) segment = 'Champions';
  else if (r_score >= 3 && m_score >= 4) segment = 'Loyal Customers';
  else if (r_score >= 4 && f_score <= 2) segment = 'New Customers';
  else if (r_score <= 2 && f_score >= 3 && m_score >= 3) segment = 'At Risk';
  else if (r_score <= 2 && f_score >= 4 && m_score >= 4) segment = 'Cant Lose Them';
  else if (r_score <= 2 && f_score <= 2) segment = 'Lost';
  else if (r_score == 3 && f_score <= 2) segment = 'Need Attention';

  return { ...u, r_score, f_score, m_score, recency_days: recency, segment };
});

// Segment summary
const summary = {};
scored.forEach(u => {
  if (!summary[u.segment]) summary[u.segment] = { segment: u.segment, count: 0, total_ltv: 0 };
  summary[u.segment].count++;
  summary[u.segment].total_ltv += parseFloat(u.lifetime_value || 0);
});
const seg_summary = Object.values(summary).sort((a,b) => b.total_ltv - a.total_ltv);

return [{ json: { scored_users: scored, segment_summary: seg_summary, total_users: scored.length } }];

// ── Build analysis package for Claude ────────────────────────
const rfm_data   = $('RFM Scoring').first().json;
const shops      = $('Query Shop Performance').all().map(i => i.json);
const products   = $('Query Product Performance').all().map(i => i.json);
const categories = $('Query Category Revenue').all().map(i => i.json);

const total_revenue = shops.reduce((s, sh) => s + parseFloat(sh.revenue || 0), 0);
const top_shops     = shops.slice(0, 5);
const top_products  = products.slice(0, 10);
const segments      = rfm_data.segment_summary;

const analysis_package = {
  generated_at:    new Date().toISOString(),
  total_users:     rfm_data.total_users,
  total_revenue_aed: total_revenue.toFixed(2),
  segment_summary: segments,
  top_shops:       top_shops,
  top_products:    top_products,
  categories:      categories,
};

return [{ json: { analysis_package } }];

// ── Assemble final report payload ────────────────────────────
const pkg      = $('Build Analysis Package').first().json.analysis_package;
const narrative = $('Claude — Generate Report').first().json.text || 
                  $('Claude — Generate Report').first().json.content || 
                  'Report generation failed';

const report = {
  title:         'Zabehaty Weekly Analytics Report',
  generated_at:  pkg.generated_at,
  kpis: {
    total_buyers:      pkg.total_users,
    platform_revenue:  `AED ${parseFloat(pkg.total_revenue_aed).toLocaleString()}`,
    segments:          pkg.segment_summary.length,
  },
  narrative,
  top_shops:    pkg.top_shops,
  top_products: pkg.top_products,
};

return [{ json: { report, narrative_text: narrative } }];

// Prep Google Sheets row
const r = $('Assemble Report').first().json.report;
return [{
  json: {
    timestamp:      r.generated_at,
    total_buyers:   r.kpis.total_buyers,
    revenue:        r.kpis.platform_revenue,
    narrative:      r.narrative.substring(0, 5000),
  }
}];

// Final status
const r = $('Assemble Report').first().json.report;
console.log('Report generated:', r.generated_at);
console.log('Total buyers analysed:', r.kpis.total_buyers);
return [{ json: { status: 'success', report_title: r.title, generated_at: r.generated_at } }];
